const query = $input.first().json.query || {};
const key = String(query.key || '').toLowerCase();
const PORTFOLIOS = { mario: '1208210821231026', hugo: '1207904722398091', carlos: '1212391476899288' };
const gid = PORTFOLIOS[key];
if (!gid) throw new Error('Portfolio desconocido: ' + key);
return [{ json: { portfolioGid: gid } }];

const data = $input.first().json;
const items = data.data || [];
const proyectos = items
  .filter(p => !p.archived)
  .map(p => ({ gid: p.gid, name: p.name }))
  .sort((a, b) => a.name.localeCompare(b.name));
return [{ json: { result: proyectos } }];

const query = $input.first().json.query || {};
const gid = String(query.gid || '');
if (!gid) throw new Error('Falta gid de proyecto');
return [{ json: { gid } }];

const data = $input.first().json;
const tasks = (data.data || [])
  .filter(t => !t.completed)
  .map(t => ({ gid: t.gid, name: t.name, esSubtarea: false }));
return [{ json: { result: tasks } }];

const q = $input.first().json.query || {};
const b = $input.first().json.body || {};
const taskGid = String(q.gid || '');
if (!taskGid) { throw new Error('Falta gid de tarea'); }
const resumen = b.resumen || '';
const youtubeUrl = b.youtubeUrl || '';
const asistencia = b.asistencia || 'Show';
const duracion = b.duracion || 0;
const fecha = b.fecha || '';
const SHOW_FIELD_GID = '1211792508172622';
const SHOW_OPTIONS = { 'Show': '1212358671286114', 'No Show': '1211792508172623' };
const meses = { enero:'01', febrero:'02', marzo:'03', abril:'04', mayo:'05', junio:'06', julio:'07', agosto:'08', septiembre:'09', octubre:'10', noviembre:'11', diciembre:'12' };
let fechaISO = null;
const partes = String(fecha).toLowerCase().split(' de ');
if (partes.length === 3 && meses[partes[1].trim()]) { fechaISO = partes[2].trim() + '-' + meses[partes[1].trim()] + '-' + ('0' + partes[0].trim()).slice(-2); }
const NL = String.fromCharCode(10);
const linea = '──────────────────────────────';
const notas = '📹 Grabación: ' + (youtubeUrl || 'Pendiente') + NL + linea + NL + NL + resumen;
const data = { notes: notas, completed: true, custom_fields: { [SHOW_FIELD_GID]: SHOW_OPTIONS[asistencia] || SHOW_OPTIONS['Show'] } };
if (fechaISO) { data.start_on = fechaISO; data.due_on = fechaISO; }
const minutos = parseInt(duracion, 10) || 0;
const timeBody = { data: { duration_minutes: minutos } };
if (fechaISO) { timeBody.data.entered_on = fechaISO; }
return [{ json: { taskGid, updateBody: { data: data }, timeBody, minutos } }];

const b = $input.first().json.body || {};
const notas = b.notas || '';
const titulo = b.titulo || '';
const fecha = b.fecha || '';
const participantes = b.participantes || '';
const correos = b.correosInvitados || '';
const NL = String.fromCharCode(10);
const lineas = [
  'Eres asistente de implementacion de software hostelero (Yurest).',
  'Genera el cuerpo de un email de resumen de sesion en espanol a partir de las notas proporcionadas.',
  '',
  'Responde UNICAMENTE con un JSON valido con esta estructura exacta (sin markdown):',
  '{',
  '  "intro": "Frase introductoria breve y concreta sobre lo que se trabajo",',
  '  "titulo": ' + JSON.stringify(titulo) + ',',
  '  "fecha": ' + JSON.stringify(fecha) + ',',
  '  "participantes": ' + JSON.stringify(participantes) + ',',
  '  "correos_invitados": ' + JSON.stringify(correos) + ',',
  '  "objetivo": "Una frase clara con el objetivo principal de la sesion",',
  '  "temas_discutidos": [{"titulo": "Nombre del tema", "descripcion": "Explicacion tecnica del punto"}],',
  '  "puntos_importantes": [{"titulo": "Titulo breve", "descripcion": "Detalle del acuerdo"}],',
  '  "tareas_pendientes": [{"titulo": "Titulo breve", "descripcion": "Accion pendiente SIN responsable"}],',
  '  "proxima_sesion": "Tema, fecha y hora si se menciona; vacio si no hay info",',
  '  "duracion_minutos": 0',
  '}',
  'REGLAS:',
  '- 3 a 7 elementos por seccion maximo.',
  '- Se concreto y tecnico, usa nombres reales de modulos/productos.',
  '- No inventes informacion que no este en las notas.',
  '- En tareas_pendientes NUNCA incluyas nombres de responsables, solo la accion.',
  '- Si una seccion no tiene info, devuelvela como array vacio [].',
  '- duracion_minutos: extrae la duracion en minutos si aparece en las notas; si no, 0.',
  '',
  'NOTAS DE LA SESION:',
  notas
];
const prompt = lineas.join(NL);
const openaiBody = { model: 'gpt-4o', max_tokens: 3000, response_format: { type: 'json_object' }, messages: [{ role: 'user', content: prompt }] };
return [{ json: { openaiBody } }];

const resp = $input.first().json;
let content = '';
if (resp.choices && resp.choices[0] && resp.choices[0].message) { content = resp.choices[0].message.content || ''; }
const start = content.indexOf('{');
const end = content.lastIndexOf('}');
if (start === -1 || end === -1) { throw new Error('OpenAI no devolvio JSON'); }
const datos = JSON.parse(content.slice(start, end + 1));
return [{ json: { result: { datos: datos } } }];

const q = $input.first().json.query || {};
const persona = String(q.person || 'mario').toLowerCase();
const CAL = { mario: 'm.labrandero@yurest.com', carlos: 'c.aparicio@yurest.com', hugo: 'h.zalazar@yurest.com' };
const calendarId = CAL[persona];
if (!calendarId) { throw new Error('Persona no valida: ' + persona); }
const hoy = new Date();
let dl = 0; const limite = new Date(hoy);
while (dl < 7) { limite.setDate(limite.getDate() - 1); const dow = limite.getDay(); if (dow !== 0 && dow !== 6) { dl++; } }
limite.setHours(0,0,0,0);
const apiUrl = 'https://www.googleapis.com/calendar/v3/calendars/' + encodeURIComponent(calendarId) + '/events';
return [{ json: { apiUrl, emailOrg: calendarId, timeMin: limite.toISOString(), timeMax: hoy.toISOString() } }];

const resp = $input.first().json;
const items = resp.items || [];
const emailOrg = String(($('Prep Calendar Query').item.json.emailOrg) || '').toLowerCase();
const SKIP = ['tareas indirectas','comida','out of office','fuera de oficina'];
const map = new Map();
for (const evt of items) {
  const organizador = String((evt.organizer && evt.organizer.email) || '').toLowerCase();
  const creador = String((evt.creator && evt.creator.email) || '').toLowerCase();
  if (organizador !== emailOrg && creador !== emailOrg) { continue; }
  if (!evt.summary) { continue; }
  const low = evt.summary.toLowerCase();
  if (SKIP.some(x => low.includes(x))) { continue; }
  const fechaObj = new Date((evt.start && (evt.start.dateTime || evt.start.date)) || Date.now());
  let titulo = evt.summary;
  const ng = titulo.toLowerCase().lastIndexOf(' - notas de gemini');
  if (ng !== -1) { titulo = titulo.slice(0, ng); }
  const parts = titulo.split(' - ');
  if (parts.length > 1) { const last = parts[parts.length - 1].trim(); const yr = last.slice(0,4); if (last.charAt(4) === '/' && yr >= '2000' && yr <= '2099') { parts.pop(); } titulo = parts.join(' - '); }
  titulo = titulo.trim();
  const correos = (evt.attendees || []).map(a => a.displayName || a.email).filter(Boolean).join(', ');
  let docId = null;
  if (evt.attachments) { for (const att of evt.attachments) { if (att.title && att.title.toLowerCase().includes('notas de gemini') && att.fileId) { docId = att.fileId; break; } } }
  const clave = docId || ('evt_' + evt.id);
  if (map.has(clave)) { continue; }
  map.set(clave, { id: clave, docId: docId, name: titulo, titulo: titulo, correosInvitados: correos, tieneNotas: !!docId, fechaObj: fechaObj, fecha: fechaObj.toLocaleDateString('es-ES', { day:'2-digit', month:'2-digit', year:'numeric' }) });
}
const todas = Array.from(map.values()).sort((a,b) => b.fechaObj - a.fechaObj);
const vistos = new Set();
const sesiones = [];
for (const s of todas) { const k = s.titulo + '__' + s.fecha; if (vistos.has(k)) { continue; } vistos.add(k); sesiones.push({ id: s.id, docId: s.docId, tieneNotas: s.tieneNotas, name: s.name, titulo: s.titulo, fecha: s.fecha, fechaISO: s.fechaObj.toISOString(), correosInvitados: s.correosInvitados }); }
return [{ json: { result: sesiones } }];

const q = $input.first().json.query || {};
const docId = String(q.docId || '');
if (!docId) { throw new Error('Falta docId'); }
const base = 'https://www.googleapis.com/drive/v3/files/' + encodeURIComponent(docId);
return [{ json: { docId, driveUrl: base, exportUrl: base + '/export' } }];

const docs = $input.first().json;
let contenido = '';
if (typeof docs === 'string') { contenido = docs; } else if (docs && typeof docs.data === 'string') { contenido = docs.data; } else if (docs && docs.body) { contenido = docs.body; }
const drive = $('GET Drive Meta').item.json;
const docName = drive.name || '';
let titulo = docName;
const ng = titulo.toLowerCase().lastIndexOf(' - notas de gemini');
if (ng !== -1) { titulo = titulo.slice(0, ng); }
const parts = titulo.split(' - ');
if (parts.length > 1) { const last = parts[parts.length - 1].trim(); const yr = last.slice(0,4); if (last.charAt(4) === '/' && yr >= '2000' && yr <= '2099') { parts.pop(); } titulo = parts.join(' - '); }
titulo = titulo.trim();
const fechaObj = new Date(drive.modifiedTime || Date.now());
const result = { titulo: titulo, fecha: fechaObj.toLocaleDateString('es-ES', { day:'numeric', month:'long', year:'numeric' }), correosInvitados: '', participantes: '', notas: contenido, docName: docName, duracion: 0 };
return [{ json: { result } }];
